vector<string> readBinaryWatch(int turnedOn) {
    vector<string> res;
    for (int h = 0; h < 12; ++h) {
        for (int m = 0; m < 60; ++m) {
            // __builtin_popcount counts set bits in C++
            if (__builtin_popcount(h) + __builtin_popcount(m) == turnedOn) {
                string hr = to_string(h);
                string min = (m < 10) ? "0" + to_string(m) : to_string(m);
                res.push_back(hr + ":" + min);
            }
        }
    }
    return res;
}

