def subsetXORSum(nums):
    def dfs(i, curr_xor):
        if i == len(nums):
            return curr_xor
        # Sum of choice 1 (exclude) and choice 2 (include)
        exclude = dfs(i + 1, curr_xor)
        include = dfs(i + 1, curr_xor ^ nums[i])
        return exclude + include

    return dfs(0, 0)

