int subsetXORSum(vector<int>& nums) {
    auto dfs = [&](auto& self, int i, int curr_xor) -> int {
        if (i == nums.size()) {
            return curr_xor;
        }
        int exclude = self(self, i + 1, curr_xor);
        int include = self(self, i + 1, curr_xor ^ nums[i]);
        return exclude + include;
    };
    return dfs(dfs, 0, 0);
}

