vector<string> generateBin(int n) {
    vector<string> res;
    auto dfs = [&](auto& self, string curr) -> void {
        if (curr.size() == n) {
            res.push_back(curr);
            return;
        }
        self(self, curr + "0");
        self(self, curr + "1");
    };
    dfs(dfs, "");
    return res;
}

vector<vector<int>> subsets(vector<int>& nums) {
    vector<vector<int>> res;
    vector<int> path;
    auto dfs = [&](auto& self, int i) -> void {
        if (i == nums.size()) {
            res.push_back(path);
            return;
        }
        // Include
        path.push_back(nums[i]);
        self(self, i + 1);
        path.pop_back(); // Backtrack

        // Exclude
        self(self, i + 1);
    };
    dfs(dfs, 0);
    return res;
}

vector<vector<int>> permute(vector<int>& nums) {
    vector<vector<int>> res;
    int n = nums.size();
    auto backtrack = [&](auto& self, int first) -> void {
        if (first == n) {
            res.push_back(nums);
            return;
        }
        for (int i = first; i < n; ++i) {
            swap(nums[first], nums[i]);
            self(self, first + 1);
            swap(nums[first], nums[i]); // Backtrack
        }
    };
    backtrack(backtrack, 0);
    return res;
}

vector<vector<int>> combinationSum(vector<int>& candidates, int target) {
    vector<vector<int>> res;
    vector<int> path;

    auto dfs = [&](auto& self, int i, int total) -> void {
        if (total == target) {
            res.push_back(path);
            return;
        }
        if (total > target || i >= candidates.size()) return;

        // Include candidates[i] (re-pass index i for unlimited usage)
        path.push_back(candidates[i]);
        self(self, i, total + candidates[i]);
        path.pop_back(); // Backtrack

        // Exclude candidates[i] (step forward)
        self(self, i + 1, total);
    };

    dfs(dfs, 0, 0);
    return res;
}

vector<vector<string>> solveNQueens(int n) {
    vector<vector<string>> res;
    vector<string> board(n, string(n, '.'));

    unordered_set<int> cols;
    unordered_set<int> pos_diag;
    unordered_set<int> neg_diag;

    auto backtrack = [&](auto& self, int r) -> void {
        if (r == n) {
            res.push_back(board);
            return;
        }
        for (int c = 0; c < n; ++c) {
            if (cols.count(c) || pos_diag.count(r + c) || neg_diag.count(r - c)) {
                continue;
            }
            cols.insert(c);
            pos_diag.insert(r + c);
            neg_diag.insert(r - c);
            board[r][c] = 'Q';

            self(self, r + 1);

            cols.erase(c);
            pos_diag.erase(r + c);
            neg_diag.erase(r - c);
            board[r][c] = '.';
        }
    };

    backtrack(backtrack, 0);
    return res;
}

