def solveSudoku(board):
    def is_valid(r, c, val):
        for i in range(9):
            # Check row
            if board[r][i] == val:
                return False
            # Check column
            if board[i][c] == val:
                return False
            # Check 3x3 subgrid
            sub_r = 3 * (r // 3) + i // 3
            sub_c = 3 * (c // 3) + i % 3
            if board[sub_r][sub_c] == val:
                return False
        return True

    def solve():
        for r in range(9):
            for c in range(9):
                if board[r][c] == '.':
                    for num in '123456789':
                        if is_valid(r, c, num):
                            board[r][c] = num
                            if solve():
                                return True
                            board[r][c] = '.' # Backtrack
                    return False # No number fits
        return True # Board complete

    solve()

