void solveSudoku(vector<vector<char>>& board) {
    auto isValid = [&](int r, int c, char val) -> bool {
        for (int i = 0; i < 9; ++i) {
            if (board[r][i] == val) return false;
            if (board[i][c] == val) return false;
            int sub_r = 3 * (r / 3) + i / 3;
            int sub_c = 3 * (c / 3) + i % 3;
            if (board[sub_r][sub_c] == val) return false;
        }
        return true;
    };

    auto solve = [&](auto& self) -> bool {
        for (int r = 0; r < 9; ++r) {
            for (int c = 0; c < 9; ++c) {
                if (board[r][c] == '.') {
                    for (char num = '1'; num <= '9'; ++num) {
                        if (isValid(r, c, num)) {
                            board[r][c] = num;
                            if (self(self)) return true;
                            board[r][c] = '.'; // Backtrack
                        }
                    }
                    return false;
                }
            }
        }
        return true;
    };

    solve(solve);
}

