class TrieNode:
    def __init__(self):
        self.children = {}
        self.word = None

def findWords(board, words):
    # Build Trie
    root = TrieNode()
    for w in words:
        curr = root
        for char in w:
            if char not in curr.children:
                curr.children[char] = TrieNode()
            curr = curr.children[char]
        curr.word = w

    r, c = len(board), len(board[0])
    res = set()

    def dfs(i, j, node):
        char = board[i][j]
        if char not in node.children:
            return

        next_node = node.children[char]
        if next_node.word:
            res.add(next_node.word)
            # Optimization: set word to None to prevent duplicate matches
            next_node.word = None

        board[i][j] = '#'
        for di, dj in [(1,0), (-1,0), (0,1), (0,-1)]:
            ni, nj = i + di, j + dj
            if 0 <= ni < r and 0 <= nj < c and board[ni][nj] != '#':
                dfs(ni, nj, next_node)
        board[i][j] = char # Backtrack

    for i in range(r):
        for j in range(c):
            dfs(i, j, root)

    return list(res)

