struct TrieNode {
    unordered_map<char, TrieNode*> children;
    string word = "";
};

vector<string> findWords(vector<vector<char>>& board, vector<string>& words) {
    TrieNode* root = new TrieNode();
    for (const string& w : words) {
        TrieNode* curr = root;
        for (char c : w) {
            if (!curr->children.count(c)) curr->children[c] = new TrieNode();
            curr = curr->children[c];
        }
        curr->word = w;
    }

    int r = board.size();
    int c = board[0].size();
    vector<string> res;

    auto dfs = [&](auto& self, int i, int j, TrieNode* node) -> void {
        char ch = board[i][j];
        if (!node->children.count(ch)) return;

        TrieNode* next_node = node->children[ch];
        if (!next_node->word.empty()) {
            res.push_back(next_node->word);
            next_node->word = ""; // Avoid duplicates
        }

        board[i][j] = '#'; // Mark visited
        int dirs[4][2] = {{1,0}, {-1,0}, {0,1}, {0,-1}};
        for (auto& dir : dirs) {
            int ni = i + dir[0];
            int nj = j + dir[1];
            if (ni >= 0 && ni < r && nj >= 0 && nj < c && board[ni][nj] != '#') {
                self(self, ni, nj, next_node);
            }
        }
        board[i][j] = ch; // Backtrack
    };

    for (int i = 0; i < r; ++i) {
        for (int j = 0; j < c; ++j) {
            dfs(dfs, i, j, root);
        }
    }
    return res;
}
